class Solution:
    def shortestPathLength(self, graph):
        n = len(graph)
        if n <= 1:
            return 0
        full = (1 << n) - 1
        from collections import deque
        # plain BFS without a visited-set optimisation beyond a dict of distances
        start = [(i, 1 << i) for i in range(n)]
        dist = {}
        dq = deque()
        for node, mask in start:
            dist[(node, mask)] = 0
            dq.append((node, mask))
        while dq:
            node, mask = dq.popleft()
            d = dist[(node, mask)]
            if mask == full:
                return d
            for nb in graph[node]:
                nmask = mask | (1 << nb)
                if (nb, nmask) not in dist:
                    dist[(nb, nmask)] = d + 1
                    dq.append((nb, nmask))
        return 0

