from collections import deque
class Solution:
    def shortestPathLength(self, graph):
        n = len(graph)
        if n <= 1:
            return 0
        full = (1 << n) - 1
        seen = set()
        dq = deque()
        for i in range(n):
            state = (i, 1 << i)
            dq.append((i, 1 << i, 0))
            seen.add(state)
        while dq:
            node, mask, dist = dq.popleft()
            if mask == full:
                return dist
            for nb in graph[node]:
                nmask = mask | (1 << nb)
                if (nb, nmask) not in seen:
                    seen.add((nb, nmask))
                    dq.append((nb, nmask, dist + 1))
        return 0

