var shortestPathLength = function(graph) {
    const n = graph.length;
    if (n <= 1) return 0;
    const full = (1 << n) - 1;
    const seen = new Set();
    let queue = [];
    for (let i = 0; i < n; i++) {
        queue.push([i, 1 << i]);
        seen.add(i * (1 << n) + (1 << i));
    }
    let dist = 0;
    while (queue.length) {
        const next = [];
        for (const [node, mask] of queue) {
            if (mask === full) return dist;
            for (const nb of graph[node]) {
                const nmask = mask | (1 << nb);
                const key = nb * (1 << n) + nmask;
                if (!seen.has(key)) {
                    seen.add(key);
                    next.push([nb, nmask]);
                }
            }
        }
        queue = next;
        dist++;
    }
    return 0;
};
